-- PostgreSQL 种子数据（从 MySQL 导出转换）
-- 此脚本在首次部署后手动执行: 
--   docker exec devops-postgres psql -U devops -d autoops -f /seed/seed_data.sql
-- 包含: 系统菜单、角色、用户、部门、业务组

-- 禁用触发器（避免外键约束冲突）
SET session_replication_role = replica;


-- 重置序列到最大值（避免后续插入 ID 冲突）
DO $$
DECLARE
  t RECORD;
BEGIN
  FOR t IN
    SELECT table_name, column_name
    FROM information_schema.columns
    WHERE table_schema = 'public'
      AND column_default LIKE 'nextval%'
  LOOP
    EXECUTE format(
      'SELECT setval(pg_get_serial_sequence(''%I'', ''%I''), COALESCE((SELECT MAX(%I) FROM %I), 1))',
      t.table_name, t.column_name, t.column_name, t.table_name
    );
  END LOOP;
END $$;

-- 恢复触发器
SET session_replication_role = DEFAULT;

\echo 'Seed data loaded successfully!'
